import{_ as a,c as e,o as n,d as s}from"./app.2d0d4a31.js";const m='{"title":"Autenticaci\xF3n - Vue SPA","description":"","frontmatter":{},"headers":[{"level":2,"title":"Puntos finales de autenticaci\xF3n y CORS","slug":"puntos-finales-de-autenticacion-y-cors"},{"level":2,"title":"Sesiones, Cookies y CSRF","slug":"sesiones-cookies-y-csrf"},{"level":2,"title":"Protecci\xF3n de Rutas y Mantenimiento del Estado","slug":"proteccion-de-rutas-y-mantenimiento-del-estado"},{"level":2,"title":"Plantillas de P\xE1gina (Vistas) y Descripci\xF3n de Componentes","slug":"plantillas-de-pagina-vistas-y-descripcion-de-componentes"},{"level":3,"title":"Componente de Registro","slug":"componente-de-registro"},{"level":3,"title":"Componente de Inicio de Sesi\xF3n","slug":"componente-de-inicio-de-sesion"},{"level":3,"title":"Componente de Cierre de Sesi\xF3n","slug":"componente-de-cierre-de-sesion"},{"level":3,"title":"Vista de Tablero (Ruta Protegida)","slug":"vista-de-tablero-ruta-protegida"},{"level":3,"title":"Forgot Password View","slug":"forgot-password-view"},{"level":3,"title":"Reset Password View","slug":"reset-password-view"},{"level":3,"title":"Update Password Component","slug":"update-password-component"},{"level":3,"title":"Email Verification","slug":"email-verification"},{"level":3,"title":"Flash Message Component","slug":"flash-message-component"}],"relativePath":"vue/vue-authentication.md"}',t={},o=s(`<h1 id="autenticacion-vue-spa" tabindex="-1">Autenticaci\xF3n - Vue SPA <a class="header-anchor" href="#autenticacion-vue-spa" aria-hidden="true">#</a></h1><h2 id="puntos-finales-de-autenticacion-y-cors" tabindex="-1">Puntos finales de autenticaci\xF3n y CORS <a class="header-anchor" href="#puntos-finales-de-autenticacion-y-cors" aria-hidden="true">#</a></h2><p>Primero eche un vistazo al archivo <a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/src/modules/Auth/services/index.ts" target="_blank" rel="noopener noreferrer">Servicios de Autenticaci\xF3n</a> para mantener todos los puntos finales de autenticaci\xF3n de API en un solo lugar. Los m\xE9todos en este archivo interact\xFAan con los puntos finales de Fortify que hemos configurado previamente.</p><p>En la parte superior de este archivo, se importa <a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/src/utils/Http/index.ts" target="_blank" rel="noopener noreferrer">Http</a>, el cual es un wrapper de Axios, para manejar la obtenci\xF3n de datos de nuestra API. Note que el wrapper <code>Http</code> para ser instanciado debe recibir una configuraci\xF3n <a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/src/utils/Http/init.ts" target="_blank" rel="noopener noreferrer">inicial</a> global dependiendo del uso.</p><p>Para este caso, simplemente estamos configurando solo tres propiedades:</p><div class="language-ts"><pre><code><span class="token keyword">import</span> <span class="token punctuation">{</span> useAuthStore <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@/modules/Auth/stores&#39;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> InitInterface <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&quot;./init.interface&quot;</span>

<span class="token keyword">export</span> <span class="token keyword">default</span><span class="token operator">&lt;</span>InitInterface<span class="token operator">&gt;</span> <span class="token punctuation">{</span>
  baseURL<span class="token operator">:</span> process<span class="token punctuation">.</span>env<span class="token punctuation">.</span><span class="token constant">VUE_APP_API_URL</span><span class="token punctuation">,</span>  
  withCredentials<span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span> 
  <span class="token function">handleError</span><span class="token punctuation">(</span>error<span class="token operator">:</span> <span class="token builtin">any</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">const</span> storeAuth <span class="token operator">=</span> <span class="token function">useAuthStore</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
    
    <span class="token keyword">if</span> <span class="token punctuation">(</span>error<span class="token punctuation">.</span>response
      <span class="token operator">&amp;&amp;</span> <span class="token punctuation">[</span><span class="token number">401</span><span class="token punctuation">,</span> <span class="token number">419</span><span class="token punctuation">]</span><span class="token punctuation">.</span><span class="token function">includes</span><span class="token punctuation">(</span>error<span class="token punctuation">.</span>response<span class="token punctuation">.</span>status<span class="token punctuation">)</span>    
      <span class="token operator">&amp;&amp;</span> storeAuth<span class="token punctuation">.</span>authUser 
      <span class="token operator">&amp;&amp;</span> <span class="token operator">!</span>storeAuth<span class="token punctuation">.</span>guest
    <span class="token punctuation">)</span> <span class="token punctuation">{</span>
      storeAuth<span class="token punctuation">.</span><span class="token function">logout</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
    
    <span class="token keyword">return</span> <span class="token builtin">Promise</span><span class="token punctuation">.</span><span class="token function">reject</span><span class="token punctuation">(</span>error<span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><ul><li><code>baseURL</code> contiene el valor de <code>process.<wbr>env.VUE_APP_API_URL</code>, declarada en <a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/vite.config.ts" target="_blank" rel="noopener noreferrer">vite.config.ts</a>.</li><li><code>withCredentials</code> debe ser declarada en <code>true</code>, ya que una solicitud <code>XMLHttpRequest</code> de un dominio diferente no puede establecer valores de cookies para su dominio a menos que esta se establezca en verdadero antes de realizar la solicitud.</li><li><code>handleErro</code> es una funci\xF3n personalizada para el manejo de errores.</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Es importante resaltar que esto requiere que el SPA y la API compartan el mismo dominio de nivel superior. Sin embargo, pueden colocarse en diferentes subdominios.</p></div><h2 id="sesiones-cookies-y-csrf" tabindex="-1">Sesiones, Cookies y CSRF <a class="header-anchor" href="#sesiones-cookies-y-csrf" aria-hidden="true">#</a></h2><p>Para autenticar su SPA, la p\xE1gina de inicio de sesi\xF3n primero debe realizar una solicitud al extremo <code>/sanctum/csrf-cookie</code> para inicializar la protecci\xF3n CSRF para la aplicaci\xF3n:</p><div class="language-ts"><pre><code><span class="token keyword">await</span> authClient<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token string">&quot;/sanctum/csrf-cookie&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre></div><p>Esto tambi\xE9n se aplica a cualquier otra acci\xF3n de Fortify que requiera protecci\xF3n CSRF. Tenga en cuenta las otras rutas en el m\xF3dulo <a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/src/modules/Auth/services/index.ts" target="_blank" rel="noopener noreferrer">AuthService</a> que tambi\xE9n incluyen una solicitud de obtenci\xF3n de la cookie CSRF; <code>forgotPassword</code>, <code>resetPassword</code>, etc.</p><p>Si una solicitud de inicio de sesi\xF3n tiene \xE9xito, el usuario se autentica y las solicitudes posteriores al SPA se autenticar\xE1n autom\xE1ticamente a trav\xE9s de la cookie de sesi\xF3n que emite la aplicaci\xF3n Laravel. Adem\xE1s, dado que ya hicimos una solicitud a la ruta <code>/sanctum/csrf-cookie</code>, las solicitudes posteriores deber\xEDan recibir autom\xE1ticamente protecci\xF3n CSRF porque Axios env\xEDa autom\xE1ticamente la cookie XSRF-TOKEN en el encabezado X-XSRF-TOKEN.</p><h2 id="proteccion-de-rutas-y-mantenimiento-del-estado" tabindex="-1">Protecci\xF3n de Rutas y Mantenimiento del Estado <a class="header-anchor" href="#proteccion-de-rutas-y-mantenimiento-del-estado" aria-hidden="true">#</a></h2><p>El m\xE9todo para proteger las rutas de su aplicaci\xF3n es bastante simple. En los archivos de rutas, como el caso del m\xF3dulo <code>Auth</code> hay un metacampo <a href="https://github.com/garethredfern/laravel-vue/blob/v1.2.7/src/router/index.js" target="_blank" rel="noopener noreferrer">requiresAuth</a>, es un valor booleano que se mantiene contra cada ruta que desea proteger. Usando el enrutador Vue antes de cada m\xE9todo, verifique si una ruta tiene un booleano <code>auth</code> de verdadero y si hay un usuario autenticado en el <a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/src/modules/Auth/stores/index.ts" target="_blank" rel="noopener noreferrer">AuthStore</a>:</p><div class="language-ts"><pre><code>router<span class="token punctuation">.</span><span class="token function">beforeEach</span><span class="token punctuation">(</span><span class="token punctuation">(</span>to<span class="token punctuation">,</span> from<span class="token punctuation">,</span> next<span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  <span class="token keyword">const</span> authUser <span class="token operator">=</span> store<span class="token punctuation">.</span>getters<span class="token punctuation">[</span><span class="token string">&quot;auth/authUser&quot;</span><span class="token punctuation">]</span><span class="token punctuation">;</span>
  <span class="token keyword">const</span> reqAuth <span class="token operator">=</span> to<span class="token punctuation">.</span>matched<span class="token punctuation">.</span><span class="token function">some</span><span class="token punctuation">(</span><span class="token punctuation">(</span>record<span class="token punctuation">)</span> <span class="token operator">=&gt;</span> record<span class="token punctuation">.</span>meta<span class="token punctuation">.</span>requiresAuth<span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token keyword">const</span> loginQuery <span class="token operator">=</span> <span class="token punctuation">{</span> path<span class="token operator">:</span> <span class="token string">&quot;/login&quot;</span><span class="token punctuation">,</span> query<span class="token operator">:</span> <span class="token punctuation">{</span> redirect<span class="token operator">:</span> to<span class="token punctuation">.</span>fullPath <span class="token punctuation">}</span> <span class="token punctuation">}</span><span class="token punctuation">;</span>

  <span class="token keyword">if</span> <span class="token punctuation">(</span>reqAuth <span class="token operator">&amp;&amp;</span> <span class="token operator">!</span>authUser<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    store<span class="token punctuation">.</span><span class="token function">dispatch</span><span class="token punctuation">(</span><span class="token string">&quot;auth/getAuthUser&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">then</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
      <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token operator">!</span>store<span class="token punctuation">.</span>getters<span class="token punctuation">[</span><span class="token string">&quot;auth/authUser&quot;</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token function">next</span><span class="token punctuation">(</span>loginQuery<span class="token punctuation">)</span><span class="token punctuation">;</span>
      <span class="token keyword">else</span> <span class="token function">next</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
    <span class="token function">next</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// make sure to always call next()!</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre></div><p>Algunos escenarios deben manejarse aqu\xED:</p><ol><li>Si hay un usuario autenticado en estado, la ruta permite cargar la p\xE1gina.</li><li>Si no hay un usuario autenticado en el estado, haga una llamada a la API de Laravel para verificar si hay un usuario autenticado que se vincule con la sesi\xF3n. Suponiendo que lo haya, la tienda se completar\xE1 con los detalles del usuario. El enrutador permite que la p\xE1gina se cargue.</li><li>Finalmente, si no hay una sesi\xF3n v\xE1lida, redirija a la p\xE1gina de inicio de sesi\xF3n.</li></ol><p>Actualizar el navegador enviar\xE1 una solicitud GET a la API para el usuario autenticado, almacenar\xE1 los detalles en el estado. Navegar por la aplicaci\xF3n utilizar\xE1 el estado <code>auth</code> para minimizar las solicitudes de API, manteniendo las cosas \xE1giles. Esto tambi\xE9n ayuda con la seguridad. Cada vez que se obtienen datos de la API, Laravel verifica la sesi\xF3n. Si la sesi\xF3n deja de ser v\xE1lida, se env\xEDa una respuesta <code>401</code> o <code>419</code> al SPA. Manejado a trav\xE9s de un interceptor Axios, desconectando al usuario.</p><div class="language-js"><pre><code>authClient<span class="token punctuation">.</span>interceptors<span class="token punctuation">.</span>response<span class="token punctuation">.</span><span class="token function">use</span><span class="token punctuation">(</span>
  <span class="token punctuation">(</span><span class="token parameter">response</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> response<span class="token punctuation">;</span>
  <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token parameter">error</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span>error<span class="token punctuation">.</span>response<span class="token punctuation">.</span>status <span class="token operator">===</span> <span class="token number">401</span> <span class="token operator">||</span> error<span class="token punctuation">.</span>response<span class="token punctuation">.</span>status <span class="token operator">===</span> <span class="token number">419</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
      store<span class="token punctuation">.</span><span class="token function">dispatch</span><span class="token punctuation">(</span><span class="token string">&quot;auth/logout&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
    <span class="token keyword">return</span> Promise<span class="token punctuation">.</span><span class="token function">reject</span><span class="token punctuation">(</span>error<span class="token punctuation">.</span>response<span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre></div><h2 id="plantillas-de-pagina-vistas-y-descripcion-de-componentes" tabindex="-1">Plantillas de P\xE1gina (Vistas) y Descripci\xF3n de Componentes <a class="header-anchor" href="#plantillas-de-pagina-vistas-y-descripcion-de-componentes" aria-hidden="true">#</a></h2><p>Aqu\xED hay un desglose de cada uno de los componentes y vistas de Vue que se utilizan para gestionar la autenticaci\xF3n de usuarios, el restablecimiento de contrase\xF1as y la verificaci\xF3n de correo electr\xF3nico.</p><h3 id="componente-de-registro" tabindex="-1">Componente de Registro <a class="header-anchor" href="#componente-de-registro" aria-hidden="true">#</a></h3><p><a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/src/modules/Auth/views/Register/Index.vue" target="_blank" rel="noopener noreferrer">Ver archivo en GitHub</a></p><p>El componente de registro permite a los usuarios registrarse para obtener una cuenta si no tienen una. Funciona con el punto final <code>/register</code> de Fortify. Solo funciona cuando un usuario no ha iniciado sesi\xF3n, no puede usarlo para agregar usuarios si ha iniciado sesi\xF3n. Para agregar usuarios a trav\xE9s de una pantalla de administraci\xF3n, necesitar\xEDamos crear otro punto final de API y modificar este componente para publicarlo tambi\xE9n. Por ahora, se mantiene simplemente para registrar nuevos usuarios. Una vez que un usuario se registra correctamente, inicia sesi\xF3n autom\xE1ticamente y se le redirige al panel.</p><h3 id="componente-de-inicio-de-sesion" tabindex="-1">Componente de Inicio de Sesi\xF3n <a class="header-anchor" href="#componente-de-inicio-de-sesion" aria-hidden="true">#</a></h3><p><a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/src/modules/Auth/views/Login/Index.vue" target="_blank" rel="noopener noreferrer">Ver archivo en GitHub</a></p><p>El formulario de inicio de sesi\xF3n funciona con el punto final <code>/login</code> de Fortify. Tenga en cuenta que todos los puntos finales se mantienen en el m\xF3dulo <code>AuthService</code> que se importa en cada <code>view/component</code>. Una vez que un usuario inicia sesi\xF3n correctamente, se le redirige al panel de control.</p><h3 id="componente-de-cierre-de-sesion" tabindex="-1">Componente de Cierre de Sesi\xF3n <a class="header-anchor" href="#componente-de-cierre-de-sesion" aria-hidden="true">#</a></h3><p><a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/src/components/Logout.vue" target="_blank" rel="noopener noreferrer">Ver archivo en GitHub</a></p><p>Un componente simple que funciona con el punto final <code>/logout</code> de Fortify. Cuando se cierra la sesi\xF3n de un usuario, se env\xEDa la acci\xF3n de <code>authStore.logout()</code> que borra al usuario del <code>Store</code> y lo redirige a la vista de inicio de sesi\xF3n.</p><h3 id="vista-de-tablero-ruta-protegida" tabindex="-1">Vista de Tablero (Ruta Protegida) <a class="header-anchor" href="#vista-de-tablero-ruta-protegida" aria-hidden="true">#</a></h3><p><a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/src/modules/Auth/views/Dashboard/Index.vue" target="_blank" rel="noopener noreferrer">Ver archivo en GitHub</a></p><p>Este componente requiere autenticaci\xF3n antes de que pueda verse. Un tablero podr\xEDa mostrar mucho m\xE1s, pero lo importante aqu\xED es que est\xE1 protegido. Un usuario debe estar registrado para verlo.</p><h3 id="forgot-password-view" tabindex="-1">Forgot Password View <a class="header-anchor" href="#forgot-password-view" aria-hidden="true">#</a></h3><p><a href="https://github.com/garethredfern/laravel-vue/blob/main/src/views/ForgotPassword.vue" target="_blank" rel="noopener noreferrer">View file on GitHub</a></p><p>The forgot password view can be accessed if a user is not logged in and needs to reset their password. It works with the Fortify /forgot-password endpoint. Once the form is submitted Laravel will check the email is valid and send out a reset password email. The link in this email will have a token and the URL will point to the reset password view in the SPA.</p><h3 id="reset-password-view" tabindex="-1">Reset Password View <a class="header-anchor" href="#reset-password-view" aria-hidden="true">#</a></h3><p><a href="https://github.com/garethredfern/laravel-vue/blob/main/src/views/ResetPassword.vue" target="_blank" rel="noopener noreferrer">View file on GitHub</a></p><p>The reset password view displays a form where a user can change their password. Importantly it will also have access to the token provided by Laravel. It works with the Fortify /reset-password endpoint. When the form is submitted the users email and token are checked by Laravel. If everything was successful, a message is displayed and the user can log in.</p><h3 id="update-password-component" tabindex="-1">Update Password Component <a class="header-anchor" href="#update-password-component" aria-hidden="true">#</a></h3><p><a href="https://github.com/garethredfern/laravel-vue/blob/main/src/components/UpdatePassword.vue" target="_blank" rel="noopener noreferrer">View file on GitHub</a></p><p>This form allows a logged-in user to update their password. It works with the Fortify /user/password endpoint.</p><h3 id="email-verification" tabindex="-1">Email Verification <a class="header-anchor" href="#email-verification" aria-hidden="true">#</a></h3><p><a href="https://github.com/garethredfern/laravel-vue/blob/main/src/components/VerifyEmail.vue" target="_blank" rel="noopener noreferrer">View file on GitHub</a></p><p>Laravel provides the ability for a user to verify their email as an added layer of security. This component works with the /email/verification-notification endpoint. To get the email notification working, there is some set up required within the Laravel API. More detail in these instructions.</p><p>With this in place, the SPA will check a user is verified using the details in the auth Vuex store. If they are not, a button is displayed, when clicked the verification email will be sent by Laravel. The email will have a link to verify and return the user back to the SPA dashboard.</p><h3 id="flash-message-component" tabindex="-1">Flash Message Component <a class="header-anchor" href="#flash-message-component" aria-hidden="true">#</a></h3><p><a href="https://github.com/garethredfern/laravel-vue/blob/main/src/components/FlashMessage.vue" target="_blank" rel="noopener noreferrer">View file on GitHub</a></p><p>While the user is interacting with the API via the SPA we need to give them success and error messages. The Laravel API will be handling a lot of these messages, but we can also use catch try/catch blocks to display messages within the SPA. To keep things all in one place there is a FlashMessage component which takes a message and error prop.</p>`,50),i=[o];function p(r,c,u,l,d,h){return n(),e("div",null,i)}var f=a(t,[["render",p]]);export{m as __pageData,f as default};
